import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import Layout from '../components/Layout';
import { useAuth } from '../contexts/AuthContext';
import api from '../services/api';
import toast from 'react-hot-toast';

const DashboardContainer = styled.div`
  h1 {
    margin-bottom: 2rem;
    color: #2c3e50;
  }
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const StatCard = styled(motion.div)`
  background: ${props => props.gradient || 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'};
  color: white;
  padding: 1.5rem;
  border-radius: 10px;
  text-align: center;
`;

const StatNumber = styled.div`
  font-size: 2rem;
  font-weight: bold;
  margin-bottom: 0.5rem;
`;

const StatLabel = styled.div`
  opacity: 0.9;
`;

const QuickActions = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 1rem;
  margin-bottom: 2rem;
`;

const ActionCard = styled(motion.div)`
  background: white;
  border: 2px solid #e1e8ed;
  padding: 1.5rem;
  border-radius: 10px;
  text-align: center;
  cursor: pointer;
  transition: all 0.3s ease;
  text-decoration: none;
  color: #333;

  &:hover {
    border-color: #667eea;
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0,0,0,0.1);
  }

  i {
    font-size: 2rem;
    margin-bottom: 0.5rem;
    color: #667eea;
  }

  h3 {
    margin-bottom: 0.5rem;
  }
`;

const RecentActivity = styled.div`
  h2 {
    margin-bottom: 1rem;
    color: #2c3e50;
  }
`;

const ActivityList = styled.ul`
  list-style: none;
`;

const ActivityItem = styled.li`
  display: flex;
  align-items: center;
  gap: 1rem;
  padding: 1rem;
  border-bottom: 1px solid #f1f3f4;

  &:last-child {
    border-bottom: none;
  }
`;

const ActivityIcon = styled.div`
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: #f8f9fa;
  color: #667eea;
`;

const ActivityContent = styled.div`
  flex: 1;
`;

const ActivityTitle = styled.div`
  font-weight: 600;
  margin-bottom: 0.25rem;
`;

const ActivityTime = styled.div`
  font-size: 0.875rem;
  color: #666;
`;

const LoadingCard = styled.div`
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 2rem;
  color: #666;
`;

const StartMonitoringModal = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0,0,0,0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
`;

const ModalContent = styled.div`
  background: white;
  border-radius: 10px;
  padding: 2rem;
  width: 90%;
  max-width: 600px;
  max-height: 90vh;
  overflow-y: auto;
`;

const ModalHeader = styled.div`
  margin-bottom: 2rem;

  h2 {
    margin-bottom: 0.5rem;
  }
`;

const Dashboard = () => {
  const { user } = useAuth();
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showStartModal, setShowStartModal] = useState(false);
  const [startingSession, setStartingSession] = useState(false);
  const [sessionForm, setSessionForm] = useState({
    site_url: '',
    site_name: '',
    session_name: '',
    monitoring_interval: 30,
    max_duration: 60,
    screenshot_quality: 'high'
  });

  useEffect(() => {
    loadDashboardData();
  }, []);

  const loadDashboardData = async () => {
    try {
      const response = await api.get('/api/analytics/dashboard/');
      if (response.data.success) {
        setDashboardData(response.data.dashboard);
      }
    } catch (error) {
      console.error('Error loading dashboard data:', error);
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleStartMonitoring = async (e) => {
    e.preventDefault();
    setStartingSession(true);

    try {
      const response = await api.post('/api/monitoring/sessions/start/', sessionForm);
      
      if (response.data.success) {
        toast.success('Monitoring session started successfully!');
        setShowStartModal(false);
        setSessionForm({
          site_url: '',
          site_name: '',
          session_name: '',
          monitoring_interval: 30,
          max_duration: 60,
          screenshot_quality: 'high'
        });
        loadDashboardData(); // Refresh dashboard
      } else {
        toast.error(response.data.error || 'Failed to start monitoring session');
      }
    } catch (error) {
      console.error('Error starting monitoring:', error);
      toast.error('Failed to start monitoring session');
    } finally {
      setStartingSession(false);
    }
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setSessionForm(prev => ({
      ...prev,
      [name]: value
    }));
  };

  if (loading) {
    return (
      <Layout>
        <LoadingCard>
          <div className="spinner"></div>
          <span style={{ marginLeft: '1rem' }}>Loading dashboard...</span>
        </LoadingCard>
      </Layout>
    );
  }

  const stats = dashboardData?.quick_stats || {};
  const recentSessions = dashboardData?.recent_sessions || [];

  return (
    <Layout>
      <DashboardContainer>
        <h1>Welcome back, {user?.full_name}!</h1>
        
        <StatsGrid>
          <StatCard
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
          >
            <StatNumber>{stats.total_sessions || 0}</StatNumber>
            <StatLabel>Total Sessions</StatLabel>
          </StatCard>
          
          <StatCard
            gradient="linear-gradient(135deg, #28a745 0%, #20c997 100%)"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
          >
            <StatNumber>{stats.active_sessions || 0}</StatNumber>
            <StatLabel>Active Sessions</StatLabel>
          </StatCard>
          
          <StatCard
            gradient="linear-gradient(135deg, #ffc107 0%, #fd7e14 100%)"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
          >
            <StatNumber>{stats.total_screenshots || 0}</StatNumber>
            <StatLabel>Screenshots</StatLabel>
          </StatCard>
          
          <StatCard
            gradient="linear-gradient(135deg, #17a2b8 0%, #6f42c1 100%)"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
          >
            <StatNumber>{stats.unread_alerts || 0}</StatNumber>
            <StatLabel>Unread Alerts</StatLabel>
          </StatCard>
        </StatsGrid>

        <h2>Data Collection Categories</h2>
        <QuickActions>
          <ActionCard
            as="a"
            href="/monitoring?category=sports"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-futbol"></i>
            <h3>Sports Data</h3>
            <p>Monitor live scores & betting odds</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/monitoring?category=weather"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-cloud-sun"></i>
            <h3>Weather Data</h3>
            <p>Track forecasts & climate info</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/monitoring?category=forex"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-chart-line"></i>
            <h3>Forex Trading</h3>
            <p>Monitor currency rates & trends</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/monitoring?category=crypto"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-bitcoin"></i>
            <h3>Cryptocurrency</h3>
            <p>Track crypto prices & analysis</p>
          </ActionCard>

          <ActionCard
            as="a"
            href="/monitoring?category=ecommerce"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-shopping-cart"></i>
            <h3>E-commerce</h3>
            <p>Monitor product prices & deals</p>
          </ActionCard>

          <ActionCard
            as="a"
            href="/monitoring?category=news"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-newspaper"></i>
            <h3>News & Media</h3>
            <p>Track breaking news & updates</p>
          </ActionCard>
        </QuickActions>

        <h2>Quick Actions</h2>
        <QuickActions>
          <ActionCard
            onClick={() => setShowStartModal(true)}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-play"></i>
            <h3>Start Monitoring</h3>
            <p>Begin monitoring any website</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/sessions"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-list"></i>
            <h3>View Sessions</h3>
            <p>Manage your data collection sessions</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/analytics"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-chart-bar"></i>
            <h3>View Analytics</h3>
            <p>Check your data collection statistics</p>
          </ActionCard>
          
          <ActionCard
            as="a"
            href="/profile"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <i className="fas fa-user"></i>
            <h3>Profile Settings</h3>
            <p>Manage your account</p>
          </ActionCard>
        </QuickActions>

        <RecentActivity>
          <h2>Recent Activity</h2>
          <ActivityList>
            {recentSessions.length === 0 ? (
              <ActivityItem>
                <ActivityIcon>
                  <i className="fas fa-info"></i>
                </ActivityIcon>
                <ActivityContent>
                  <ActivityTitle>No recent activity</ActivityTitle>
                  <ActivityTime>Start your first data collection session to see activity here</ActivityTime>
                </ActivityContent>
              </ActivityItem>
            ) : (
              recentSessions.map((session, index) => (
                <ActivityItem key={session.id}>
                  <ActivityIcon>
                    <i className="fas fa-eye"></i>
                  </ActivityIcon>
                  <ActivityContent>
                    <ActivityTitle>{session.site_name || 'Data Collection Session'}</ActivityTitle>
                    <ActivityTime>
                      {session.status} • {session.screenshots_count} screenshots • 
                      {new Date(session.start_time).toLocaleString()}
                    </ActivityTime>
                  </ActivityContent>
                </ActivityItem>
              ))
            )}
          </ActivityList>
        </RecentActivity>

        {/* Start Monitoring Modal */}
        {showStartModal && (
          <StartMonitoringModal onClick={(e) => e.target === e.currentTarget && setShowStartModal(false)}>
            <ModalContent>
              <ModalHeader>
                <h2>Start New Data Collection Session</h2>
                <p>Configure your data collection session settings</p>
              </ModalHeader>
              
              <form onSubmit={handleStartMonitoring}>
                <div className="form-group">
                  <label htmlFor="site_url">Website URL *</label>
                  <input
                    type="url"
                    id="site_url"
                    name="site_url"
                    value={sessionForm.site_url}
                    onChange={handleFormChange}
                    placeholder="https://example.com"
                    required
                  />
                </div>
                
                <div className="form-group">
                  <label htmlFor="site_name">Site Name</label>
                  <input
                    type="text"
                    id="site_name"
                    name="site_name"
                    value={sessionForm.site_name}
                    onChange={handleFormChange}
                    placeholder="Friendly name for this site"
                  />
                </div>
                
                <div className="form-group">
                  <label htmlFor="session_name">Session Name</label>
                  <input
                    type="text"
                    id="session_name"
                    name="session_name"
                    value={sessionForm.session_name}
                    onChange={handleFormChange}
                    placeholder="Name for this data collection session"
                  />
                </div>
                
                <div className="form-group">
                  <label htmlFor="monitoring_interval">Collection Interval</label>
                  <select
                    id="monitoring_interval"
                    name="monitoring_interval"
                    value={sessionForm.monitoring_interval}
                    onChange={handleFormChange}
                  >
                    <option value={30}>30 seconds</option>
                    <option value={60}>1 minute</option>
                    <option value={120}>2 minutes</option>
                    <option value={300}>5 minutes</option>
                  </select>
                </div>
                
                <div className="form-group">
                  <label htmlFor="max_duration">Max Duration</label>
                  <select
                    id="max_duration"
                    name="max_duration"
                    value={sessionForm.max_duration}
                    onChange={handleFormChange}
                  >
                    <option value={10}>10 minutes</option>
                    <option value={30}>30 minutes</option>
                    <option value={60}>1 hour</option>
                    <option value={120}>2 hours</option>
                    <option value={240}>4 hours</option>
                  </select>
                </div>
                
                <div className="form-group">
                  <label htmlFor="screenshot_quality">Screenshot Quality</label>
                  <select
                    id="screenshot_quality"
                    name="screenshot_quality"
                    value={sessionForm.screenshot_quality}
                    onChange={handleFormChange}
                  >
                    <option value="standard">Standard</option>
                    <option value="high">High</option>
                    <option value="ultra">Ultra</option>
                  </select>
                </div>
                
                <div style={{ display: 'flex', gap: '1rem', marginTop: '2rem' }}>
                  <button 
                    type="submit" 
                    className="btn btn-primary" 
                    style={{ flex: 1 }}
                    disabled={startingSession}
                  >
                    {startingSession && <i className="fas fa-spinner fa-spin"></i>}
                    Start Data Collection
                  </button>
                  <button 
                    type="button" 
                    className="btn btn-secondary" 
                    style={{ flex: 1 }}
                    onClick={() => setShowStartModal(false)}
                  >
                    Cancel
                  </button>
                </div>
              </form>
            </ModalContent>
          </StartMonitoringModal>
        )}
      </DashboardContainer>
    </Layout>
  );
};

export default Dashboard;
